scwin.onpageload = function () {
  scwin.sDate = $c.date.getServerDateTime($p, "yyyyMMdd");
  scwin.strFromDate = scwin.sDate; // 현재년월일을 구한다.
  scwin.strFromDate = scwin.strFromDate.substring(0, 6);
  scwin.login = $c.data.getMemInfo($p); // 로그인 정보를 가져온다.
  scwin.privAdmin = scwin.login.privAdmin; // ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님

  scwin.wrkNo = ""; // 작업구분코드
  scwin.fromDate = ""; // 작업날짜

  scwin.vLoginCoCd = $c.gus.cfIsNull($p, scwin.login.coCd) ? "" : scwin.login.coCd; // 소속 자회사  
  scwin.vLoginCoClsCd = $c.gus.cfIsNull($p, scwin.login.coClsCd) ? "" : scwin.login.coClsCd; //회계_회사구분('CO035' : 0:동부 EXPRESS)
  scwin.vUserHomeClsCd = scwin.login.userHomeClsCd;
  scwin.isSubCompany = false;
  const codeOptions = [{
    grpCd: "CO012",
    compID: "acb_unit"
  } // 단위               
  ];
  $c.data.setCommonCode($p, codeOptions, scwin.commonCodeCallBack);
};
scwin.commonCodeCallBack = async function () {
  ds_closeYm_search.set("sysCd", "ManagementProfitAndLossEBC");
  ds_closeYm_search.set("queryId", "retrieveManagementProfitAndLossCloseYm");
  ds_closeYm_search.set("param3", ed_coCd.getValue());
  var rs = await $c.sbm.execute($p, sbm_closeYm);
  if (rs.responseJSON.resultDataSet[0].Msg == "SUCC") {
    ds_closeYm.setJSON(rs.responseJSON.GAUCE);
    // co_ds_combo1.sort("code", 0);
  }
  ;
  ica_FromDate.setValue(ds_closeYm.getCellData(0, "col1"));
  ds_hidden.set("hid_FromDate", ica_FromDate.getValue());
  acb_version.hide("");
  scwin.f_LoadVer();
  $c.gus.cfDisableKey($p);
  acb_unit.setSelectedIndex(1);
  acb_srchBookClsCd.setSelectedIndex(0);
  scwin.f_setCompanyInfo();

  // $p.setTimeout(function() {
  //     // ica_FromDate.setValue("202501");
  //     // ed_sacctDeptCd.setValue("01087");
  //     // ed_sacctDeptCd.focus();
  //     // ed_sacctDeptCd.blur();
  //     chk_lowerDeptIncluYn.setValue(1);
  //     ica_FromDate.setValue("202512");
  //     ed_sacctDeptCd.setValue("00047");
  //     ed_sacctDeptCd.focus();
  //     ed_sacctDeptCd.blur();
  // }, {"delay":50});
};

