//-------------------------------------------------------------------------
scwin.f_openPopUp = async function (orgObjCd, orgObjNm, select_code, flag) {
  var rtnList = new Array();

  // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
  if (flag == "ALL") {
    cd = "";
    nm = "";
  } else {
    cd = orgObjCd.getValue();
    nm = orgObjNm.getValue();
  }
  switch (select_code) {
    // 조회조건용 수금부서 PopUp 호출(물류 귀속부서만 POPUP에 포함)

    case '1':
      var pWhere = ds_searchMonthCostResult.get("closeYm") + ",,,,,,,,," + ed_coCd.getValue();
      udc_sacctDeptCd.setSelectId('retrieveAcctDeptCdInfo');
      udc_sacctDeptCd.cfCommonPopUp(function (rtnList) {
        if (rtnList != null) {
          if (rtnList[0] == "N/A") return;
          ds_searchMonthCostResult.set("acctDeptLvl", rtnList[6]);
        } else {
          ds_searchMonthCostResult.set("acctDeptLvl", 0);
        }
        scwin.f_resultPopUp(orgObjCd, orgObjNm, rtnList);
      }, cd, nm, "T", null, null, null, null, pWhere, "450", "500", null, null); // 귀속부서
      break;
    // 조회조건용 사업영역
    case '2':
      udc_sbizDom.setSelectId('retrieveBizDomCdInfo');
      udc_sbizDom.cfCommonPopUp(function (rtnList) {
        if (rtnList != null) {
          if (rtnList[0] == "N/A") return;
          ds_searchMonthCostResult.set("acctDeptLvl", rtnList[6]);
        } else {
          ds_searchMonthCostResult.set("acctDeptLvl", 0);
        }
        scwin.f_resultPopUp(orgObjCd, orgObjNm, rtnList);
      }, cd, nm, "T", null, null, null, null, "1,,,,,", "450", "500", null, null); // 사업영역
      break;
    default:
      await $c.gus.cfAlertMsg($p, "잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
      break;
  }
};

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
// flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
  if (flag == "CD") {
    if (orgObjCd.getValue() == orgObjCd.options.hidVal) {
      return;
    } else {
      orgObjNm.setValue("");
    }
  } else {
    if (orgObjNm.getValue() == orgObjNm.options.hidVal) {
      return;
    } else {
      orgObjCd.setValue("");
    }
  }
  if (orgObjCd.getValue().trim() != "" || flag == "NM") {
    if (orgObjNm.getValue().trim() != "" || flag == "CD") {
      orgObjCd.setValue(orgObjCd.getValue().trim());
      orgObjNm.setValue(orgObjNm.getValue().trim());
      scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
    }
  } else {
    orgObjNm.setValue("");
    orgObjCd.setValue("");
    orgObjCd.options.hidVal = "";
  }
};

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopUp = function (orgObjCd, orgObjNm, rtnList) {
  if (rtnList != null) {
    if (rtnList[0] == "N/A") return;
    orgObjCd.setValue(rtnList[0]); // 코드값
    orgObjNm.setValue(rtnList[1]); // 코드명
    orgObjCd.options.hidVal = rtnList[0]; // HIDDEN 코드값
    orgObjNm.options.hidVal = rtnList[1]; // HIDDEN 코드명
    ds_searchMonthCostResult.set("acctDeptLvl", rtnList[6]);
  } else {
    orgObjCd.setValue("");
    orgObjNm.setValue("");
    orgObjCd.options.hidVal = "";
    orgObjNm.options.hidVal = "";
    ds_searchMonthCostResult.set("acctDeptLvl", 0);
  }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  ds_searchMonthCostResult.set("distYn", "1"); // 배부포함여부를 항상 포함으로 고정함.(2006.04.13)
  if (ed_sacctDeptCd.getValue().trim() != "") {
    // 조회조건 필수사항 체크
    if (!(await $c.gus.cfValidate($p, [ica_FromDate, ed_sacctDeptCd, acb_version, ed_coCd]))) {
      return;
    }
  } else if (ed_sbizDomCd.getValue().trim() != "") {
    // 조회조건 필수사항 체크
    if (!(await $c.gus.cfValidate($p, [ica_FromDate, ed_sbizDomCd, acb_version, ed_coCd]))) {
      return;
    }
  } else {
    await $c.gus.cfAlertMsg($p, "부서 혹은 사업영역중 하나는 필수 입력 입니다.");
    return;
  }

  // 귀속부서로 조회 할 경우
  if (ed_sacctDeptCd.getValue().trim() != "") {
    ds_searchMonthCostResult.set("acctDeptCd", acb_acctDeptCd.getValue());
    ds_searchMonthCostResult.set("bizDomCd", "");
    // 사업영역으로 조회 할 경우
  } else if (ed_sbizDomCd.getValue().trim() != "") {
    if (ed_coCd.getValue() == "000") {
      ds_searchMonthCostResult.set("acctDeptCd", "00000");
    }
    ds_searchMonthCostResult.set("bizDomCd", acb_acctDeptCd.getValue());
  } else {
    await $c.gus.cfAlertMsg($p, "부서 혹은 사업영역중 하나는 필수 입력 입니다.");
    return;
  }
  $c.sbm.execute($p, sbm_searchMonthCostResult);
};

