scwin.f_LoadVer = async function () {
  // 작업구분코드 및 날짜 세팅함수 호출
  scwin.fromDate = ica_FromDate.getValue().trim();
  ds_version_search.set("sysCd", "ManagementProfitAndLossEBC");
  ds_version_search.set("queryId", "retrieveMonthEachProgressResultsVer");
  ds_version_search.set("param1", scwin.fromDate);
  var rs = await $c.sbm.execute($p, sbm_version);
  if (rs.responseJSON.resultDataSet[0].Msg == "SUCC") {
    ds_version.setJSON(rs.responseJSON.GAUCE);
    // co_ds_combo1.sort("code", 0);
  }
  ;

  /* (2006.04.18) 계획의 버전이 아닌 실적의 버전을 DISTINCT해서 가져오도록 함.
          ds_version.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC" +
                                                  "&queryId=retrieveVersionInfo" +
                                                  "&param1=" + scwin.fromDate;
  */

  await scwin.f_SetFinalVer();

  /* (2006.05.29) 버전 002(경평)으로만 조회토록 setting */
  acb_version.setSelectedIndex(0);
  acb_version.setValue("002");
};

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = async function () {
  if (ds_version.getRowCount() < 1) return;
  var index = 0;
  for (i = 0; i < ds_version.getRowCount(); i++) {
    if (ds_version.getCellData(i, "ds_version.Reset();") == 1) {
      index = i - 1;
      break;
    }
  }
  acb_version.setSelectedIndex(index);
};

