scwin.f_GetRsltsDept = async function () {
  if (ed_coCd.getValue() != "000") {
    if (ed_sacctDeptCd.getValue().trim() == "") {
      await $c.gus.cfAlertMsg($p, "부서는 필수 입력 입니다.");
      return;
    }
  }
  ds_dept_search.set("sysCd", "");
  ds_dept_search.set("queryId", "");
  ds_dept_search.set("param1", "");
  ds_dept_search.set("param2", "");
  ds_dept_search.set("param3", "");
  ds_dept_search.set("param4", "");
  ds_dept_search.set("param5", "");
  ds_dept_search.set("param7", "");

  // 사업여역이 NULL일경우 귀속부서는 필수 입력임
  if (ed_sacctDeptCd.getValue().trim() != "") {
    // 조회조건 필수사항 체크
    if (!(await $c.gus.cfValidate($p, [ica_FromDate, ed_sacctDeptCd, acb_version]))) {
      return;
    }
    ds_dept_search.set("sysCd", "ManagementProfitAndLossEBC");
    ds_dept_search.set("queryId", "retrievePlanComparisonResultsAcctDept");
    ds_dept_search.set("param1", ed_sacctDeptCd.getValue().trim());
    ds_dept_search.set("param2", ica_FromDate.getValue().trim());
    ds_dept_search.set("param3", ds_searchMonthCostResult.get("lowerDeptIncluYn"));
    ds_dept_search.set("param4", ds_searchMonthCostResult.get("acctDeptLvl"));
    ds_dept_search.set("param5", ds_searchMonthCostResult.get("ver"));
    ds_dept_search.set("param7", ed_coCd.getValue());

    // 귀속부서가 NULL일경우 사업영역은 필수임
  } else if (ed_sbizDomCd.getValue().trim() != "") {
    // 조회조건 필수사항 체크
    if (!(await $c.gus.cfValidate($p, [ica_FromDate, ed_sbizDomCd, acb_version]))) {
      return;
    }
    ds_dept_search.set("sysCd", "BusinessDomainEBC");
    ds_dept_search.set("queryId", "retrievePlanComparisonResultsBizDomCd");
    ds_dept_search.set("param1", ed_sbizDomCd.getValue().trim());
    ds_dept_search.set("param3", ds_searchMonthCostResult.get("lowerDeptIncluYn"));
    ds_dept_search.set("param7", ed_coCd.getValue());
  } else {
    await $c.gus.cfAlertMsg($p, "부서 혹은 사업영역중 하나는 필수 입력 입니다.");
    return;
  }
  var rs = await $c.sbm.execute($p, sbm_dept);
  if (rs.responseJSON.resultDataSet[0].Msg == "SUCC") {
    // ds_dept event=OnLoadCompleted(rowCnt)>
    ds_dept.setJSON(rs.responseJSON.GAUCE);
    ds_dept.sort("col1", 0);
    scwin.f_Retrieve();
  }
  ;
};

